"""OS auto-start helpers — run Claude Dashboard at login."""

from __future__ import annotations

import logging
import sys
from pathlib import Path

from claude_dashboard import config
from claude_dashboard.config import IS_LINUX, IS_WINDOWS

logger = logging.getLogger(__name__)

_REG_RUN_PATH = r"Software\Microsoft\Windows\CurrentVersion\Run"
_REG_VALUE_NAME = "ClaudeDashboard"
_DESKTOP_FILENAME = "claude-dashboard.desktop"


def _startup_cmd() -> str:
    """Build the command string for auto-start."""
    exe = Path(sys.executable)
    log_flag = f' --debug --log-file "{config.LOG_FILE}"'
    if IS_WINDOWS:
        pythonw = exe.parent / "pythonw.exe"
        if not pythonw.exists():
            logger.warning(
                "pythonw.exe not found at %s; startup may open a console window", pythonw
            )
            pythonw = exe
        return f'"{pythonw}" -m claude_dashboard{log_flag}'
    return f'"{exe}" -m claude_dashboard{log_flag}'


def _desktop_file_path() -> Path:
    """Path to the XDG autostart .desktop file."""
    return Path.home() / ".config" / "autostart" / _DESKTOP_FILENAME


def set_run_on_startup(*, enabled: bool) -> None:
    """Write or remove the OS auto-start entry."""
    if IS_WINDOWS:
        _set_windows(enabled)
    elif IS_LINUX:
        _set_linux(enabled)
    else:
        logger.warning("Auto-start not supported on this platform")


def get_run_on_startup() -> bool:
    """Return True if the OS auto-start entry currently exists."""
    if IS_WINDOWS:
        return _get_windows()
    if IS_LINUX:
        return _get_linux()
    return False


def _set_windows(enabled: bool) -> None:
    import winreg

    try:
        key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, _REG_RUN_PATH, 0, winreg.KEY_SET_VALUE)
        try:
            if enabled:
                winreg.SetValueEx(key, _REG_VALUE_NAME, 0, winreg.REG_SZ, _startup_cmd())
                logger.info("Startup registry entry set: %s", _startup_cmd())
            else:
                try:
                    winreg.DeleteValue(key, _REG_VALUE_NAME)
                    logger.info("Startup registry entry removed")
                except FileNotFoundError:
                    pass
        finally:
            winreg.CloseKey(key)
    except Exception:
        logger.warning("Failed to update startup registry entry", exc_info=True)


def _get_windows() -> bool:
    import winreg

    try:
        key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, _REG_RUN_PATH, 0, winreg.KEY_READ)
        try:
            winreg.QueryValueEx(key, _REG_VALUE_NAME)
            return True
        except FileNotFoundError:
            return False
        finally:
            winreg.CloseKey(key)
    except Exception:
        return False


def _set_linux(enabled: bool) -> None:
    desktop_path = _desktop_file_path()
    try:
        if enabled:
            desktop_path.parent.mkdir(parents=True, exist_ok=True)
            desktop_path.write_text(
                f"""[Desktop Entry]
Type=Application
Name=Claude Dashboard
Exec={_startup_cmd()}
X-GNOME-Autostart-enabled=true
""",
                encoding="utf-8",
            )
            logger.info("XDG autostart file written: %s", desktop_path)
        else:
            desktop_path.unlink(missing_ok=True)
            logger.info("XDG autostart file removed")
    except OSError:
        logger.warning("Failed to update XDG autostart file", exc_info=True)


def _get_linux() -> bool:
    return _desktop_file_path().exists()
